import json

# Load children's books and reviews data
children_books = locals().get('var_functions.query_db:8', [])
reviews_file_path = locals().get('var_functions.query_db:10', '')

with open(reviews_file_path, 'r') as f:
    reviews_2020 = json.load(f)

# Check if ratings are strings or numbers
numeric_ratings = []
for r in reviews_2020:
    try:
        numeric_ratings.append(float(r['rating']))
    except:
        numeric_ratings.append(r['rating'])

# Count data types
dtype_counts = {}
for val in numeric_ratings[:50]:
    dtype_counts[str(type(val).__name__)] = dtype_counts.get(str(type(val).__name__), 0) + 1

print('__RESULT__:')
print(json.dumps({
    'children_books_sample': children_books[:2],
    'reviews_sample': reviews_2020[:2],
    'rating_types': dtype_counts
}, indent=2))

